import React, { useEffect, useState } from 'react';
import axios from 'axios';
import './App.css';

type CitySummary = {
  name: string;
  country: string;
  condition: string;
  temperature_c: number;
};

type ForecastItem = {
  day: string;
  condition: string;
  min_temp_c: number;
  max_temp_c: number;
  precipitation_chance: number;
};

type WeatherDetails = {
  city: string;
  country: string;
  updated_at: string;
  condition: string;
  temperature_c: number;
  feels_like_c: number;
  humidity: number;
  wind_speed: number;
  pressure_hpa: number;
  visibility_km: number;
  forecast: ForecastItem[];
};

type Overview = {
  title: string;
  description: string;
  cities_count: number;
  highlight: {
    city: string;
    temperature_c: number;
    condition: string;
  };
};

function App() {
  const [cities, setCities] = useState<CitySummary[]>([]);
  const [selectedCity, setSelectedCity] = useState<string>('');
  const [weather, setWeather] = useState<WeatherDetails | null>(null);
  const [overview, setOverview] = useState<Overview | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string>('');

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        setLoading(true);
        const [citiesResponse, overviewResponse] = await Promise.all([
          axios.get<CitySummary[]>('/api/cities'),
          axios.get<Overview>('/api/overview'),
        ]);

        setCities(citiesResponse.data);
        setOverview(overviewResponse.data);

        if (citiesResponse.data.length > 0) {
          setSelectedCity(citiesResponse.data[0].name);
        }
      } catch (requestError) {
        setError('Не удалось загрузить список городов и сводку.');
        console.error(requestError);
      } finally {
        setLoading(false);
      }
    };

    loadInitialData();
  }, []);

  useEffect(() => {
    if (!selectedCity) {
      return;
    }

    const loadWeather = async () => {
      try {
        setError('');
        const response = await axios.get<WeatherDetails>('/api/weather', {
          params: { city: selectedCity },
        });
        setWeather(response.data);
      } catch (requestError) {
        setError('Не удалось загрузить данные о погоде.');
        console.error(requestError);
      }
    };

    loadWeather();
  }, [selectedCity]);

  const formatTemperature = (temperature: number) => {
    const sign = temperature > 0 ? '+' : '';
    return `${sign}${temperature}°C`;
  };

  return (
    <div className="app-shell">
      <main className="page">
        <section className="hero">
          <div className="hero__content">
            <span className="eyebrow">Weather Service</span>
            <h1>Погода по городам </h1>
            <p>
              Сервис показывает текущие погодные условия, ключевые метрики и
              короткий прогноз на несколько дней вперед.
            </p>
          </div>

          <div className="hero__panel">
            <p className="hero__panel-label">{overview?.title ?? 'Сводка'}</p>
            <h2>{overview?.highlight.city ?? 'Загрузка...'}</h2>
            <p className="hero__temperature">
              {overview ? formatTemperature(overview.highlight.temperature_c) : '--'}
            </p>
            <p className="hero__condition">{overview?.highlight.condition ?? ''}</p>
            <p className="hero__meta">
              Городов в сервисе: {overview?.cities_count ?? 0}
            </p>
          </div>
        </section>

        <section className="dashboard">
          <div className="controls-card">
            <div>
              <p className="section-label">Выбор города</p>
              <h3>Выберите локацию</h3>
            </div>

            <div className="city-grid">
              {cities.map((city) => (
                <button
                  key={city.name}
                  className={`city-chip ${selectedCity === city.name ? 'city-chip--active' : ''}`}
                  onClick={() => setSelectedCity(city.name)}
                  type="button"
                >
                  <span>{city.name}</span>
                  <small>
                    {formatTemperature(city.temperature_c)} · {city.condition}
                  </small>
                </button>
              ))}
            </div>
          </div>

          <div className="weather-card">
            {loading && <p className="status">Загружаем данные...</p>}
            {!loading && error && <p className="status status--error">{error}</p>}

            {!loading && weather && (
              <>
                <div className="weather-card__header">
                  <div>
                    <p className="section-label">Сейчас</p>
                    <h2>
                      {weather.city}, {weather.country}
                    </h2>
                    <p className="updated-at">Обновлено: {weather.updated_at}</p>
                  </div>

                  <div className="weather-card__hero-value">
                    {formatTemperature(weather.temperature_c)}
                  </div>
                </div>

                <p className="weather-condition">{weather.condition}</p>

                <div className="metrics-grid">
                  <article className="metric">
                    <span>Ощущается как</span>
                    <strong>{formatTemperature(weather.feels_like_c)}</strong>
                  </article>
                  <article className="metric">
                    <span>Влажность</span>
                    <strong>{weather.humidity}%</strong>
                  </article>
                  <article className="metric">
                    <span>Ветер</span>
                    <strong>{weather.wind_speed} м/с</strong>
                  </article>
                  <article className="metric">
                    <span>Давление</span>
                    <strong>{weather.pressure_hpa} гПа</strong>
                  </article>
                  <article className="metric">
                    <span>Видимость</span>
                    <strong>{weather.visibility_km} км</strong>
                  </article>
                </div>
              </>
            )}
          </div>
        </section>

        <section className="forecast-card">
          <div className="forecast-card__header">
            <div>
              <p className="section-label">Прогноз</p>
              <h3>Ближайшие дни</h3>
            </div>
            <p>{overview?.description}</p>
          </div>

          <div className="forecast-grid">
            {weather?.forecast.map((day) => (
              <article className="forecast-item" key={day.day}>
                <p className="forecast-item__day">{day.day}</p>
                <strong>{day.condition}</strong>
                <p>
                  {formatTemperature(day.min_temp_c)} / {formatTemperature(day.max_temp_c)}
                </p>
                <span>Осадки: {day.precipitation_chance}%</span>
              </article>
            ))}
          </div>
        </section>
      </main>
    </div>
  );
}

export default App;
